CREATE TABLE roles (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(40) UNIQUE NOT NULL, permissions JSON NOT NULL, created_at DATETIME NOT NULL);
CREATE TABLE users (id BIGINT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(40) UNIQUE NOT NULL, email VARCHAR(190) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, role VARCHAR(30) NOT NULL DEFAULT 'user', status ENUM('active','suspended','banned','deleted') NOT NULL DEFAULT 'active', two_factor_secret VARCHAR(255), email_verified TINYINT(1) NOT NULL DEFAULT 0, last_login_at DATETIME, created_at DATETIME NOT NULL, INDEX(role), INDEX(status));
CREATE TABLE channels (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, name VARCHAR(100) NOT NULL, slug VARCHAR(140) UNIQUE NOT NULL, description TEXT, avatar_path VARCHAR(255), banner_path VARCHAR(255), website VARCHAR(255), social_links JSON, verified TINYINT(1) NOT NULL DEFAULT 0, subscribers BIGINT NOT NULL DEFAULT 0, created_at DATETIME NOT NULL, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE categories (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(80) NOT NULL, slug VARCHAR(100) UNIQUE NOT NULL, created_at DATETIME NOT NULL);
CREATE TABLE videos (id BIGINT AUTO_INCREMENT PRIMARY KEY, channel_id BIGINT NOT NULL, category_id INT NULL, title VARCHAR(180) NOT NULL, slug VARCHAR(220) UNIQUE NOT NULL, description TEXT, tags TEXT, video_path VARCHAR(255) NOT NULL, thumbnail_path VARCHAR(255), visibility ENUM('public','private','unlisted') NOT NULL DEFAULT 'public', status ENUM('draft','scheduled','published','processing','rejected') NOT NULL DEFAULT 'draft', published_at DATETIME NULL, duration_seconds INT DEFAULT 0, views BIGINT NOT NULL DEFAULT 0, watch_seconds BIGINT NOT NULL DEFAULT 0, likes BIGINT NOT NULL DEFAULT 0, dislikes BIGINT NOT NULL DEFAULT 0, allow_download TINYINT(1) NOT NULL DEFAULT 0, allow_embed TINYINT(1) NOT NULL DEFAULT 1, age_restricted TINYINT(1) NOT NULL DEFAULT 0, created_at DATETIME NOT NULL, FULLTEXT(title,description,tags), INDEX(status,visibility,published_at), FOREIGN KEY(channel_id) REFERENCES channels(id) ON DELETE CASCADE, FOREIGN KEY(category_id) REFERENCES categories(id) ON DELETE SET NULL);
CREATE TABLE comments (id BIGINT AUTO_INCREMENT PRIMARY KEY, video_id BIGINT NOT NULL, user_id BIGINT NOT NULL, parent_id BIGINT NULL, body TEXT NOT NULL, pinned TINYINT(1) NOT NULL DEFAULT 0, likes BIGINT NOT NULL DEFAULT 0, status ENUM('visible','hidden','deleted') NOT NULL DEFAULT 'visible', created_at DATETIME NOT NULL, FOREIGN KEY(video_id) REFERENCES videos(id) ON DELETE CASCADE, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE, FOREIGN KEY(parent_id) REFERENCES comments(id) ON DELETE CASCADE);
CREATE TABLE playlists (id BIGINT AUTO_INCREMENT PRIMARY KEY, channel_id BIGINT NOT NULL, title VARCHAR(150) NOT NULL, visibility ENUM('public','private','unlisted') NOT NULL DEFAULT 'public', created_at DATETIME NOT NULL, FOREIGN KEY(channel_id) REFERENCES channels(id) ON DELETE CASCADE);
CREATE TABLE subscriptions (subscriber_id BIGINT NOT NULL, channel_id BIGINT NOT NULL, created_at DATETIME NOT NULL, PRIMARY KEY(subscriber_id,channel_id));
CREATE TABLE wallets (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, coin VARCHAR(30) NOT NULL, pending DECIMAL(28,8) NOT NULL DEFAULT 0, approved DECIMAL(28,8) NOT NULL DEFAULT 0, locked DECIMAL(28,8) NOT NULL DEFAULT 0, UNIQUE(user_id,coin), FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE wallet_transactions (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, coin VARCHAR(30) NOT NULL, type ENUM('earning','deposit','withdrawal','tip','donation','ad_payment','refund','adjustment') NOT NULL, amount DECIMAL(28,8) NOT NULL, status ENUM('pending','approved','rejected','held') NOT NULL, reference VARCHAR(190), metadata JSON, created_at DATETIME NOT NULL, INDEX(user_id,coin,status));
CREATE TABLE withdrawals (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, coin VARCHAR(30) NOT NULL, wallet_address VARCHAR(255) NOT NULL, amount DECIMAL(28,8) NOT NULL, status ENUM('pending','approved','rejected','held','info_requested') NOT NULL DEFAULT 'pending', admin_note TEXT, created_at DATETIME NOT NULL, decided_at DATETIME NULL, FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE ad_campaigns (id BIGINT AUTO_INCREMENT PRIMARY KEY, advertiser_id BIGINT NOT NULL, type ENUM('banner','sidebar','homepage','video','pre_roll','mid_roll','sponsored_video','sponsored_channel') NOT NULL, title VARCHAR(160) NOT NULL, target_url VARCHAR(255) NOT NULL, budget DECIMAL(28,8) NOT NULL, coin VARCHAR(30) NOT NULL, starts_at DATETIME, ends_at DATETIME, targeting JSON, views BIGINT NOT NULL DEFAULT 0, clicks BIGINT NOT NULL DEFAULT 0, status ENUM('pending','approved','rejected','running','paused','expired') NOT NULL DEFAULT 'pending', created_at DATETIME NOT NULL, FOREIGN KEY(advertiser_id) REFERENCES users(id));
CREATE TABLE reports (id BIGINT AUTO_INCREMENT PRIMARY KEY, reporter_id BIGINT NULL, target_type VARCHAR(40) NOT NULL, target_id BIGINT NOT NULL, reason VARCHAR(120) NOT NULL, details TEXT, status ENUM('open','reviewing','resolved','rejected') NOT NULL DEFAULT 'open', created_at DATETIME NOT NULL);
CREATE TABLE notifications (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, channel ENUM('site','email','push') NOT NULL, subject VARCHAR(190) NOT NULL, body TEXT NOT NULL, read_at DATETIME NULL, created_at DATETIME NOT NULL, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE api_keys (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, name VARCHAR(80) NOT NULL, key_hash VARCHAR(255) NOT NULL, scopes JSON NOT NULL, last_used_at DATETIME, created_at DATETIME NOT NULL, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE audit_logs (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NULL, ip VARCHAR(64), action VARCHAR(120) NOT NULL, metadata JSON, created_at DATETIME NOT NULL, INDEX(action), INDEX(user_id));
CREATE TABLE login_history (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT, ip VARCHAR(64), user_agent VARCHAR(255), success TINYINT(1), created_at DATETIME NOT NULL);
CREATE TABLE settings (`key` VARCHAR(120) PRIMARY KEY, `value` JSON NOT NULL, updated_at DATETIME NOT NULL);
